import React from 'react';
import './CaseStudy.css';

const CaseStudy = ({ project, onClose }) => {
  const caseStudyContent = {
    "VERA Fashion Shopping App UI": {
      hero: "/cover page of plant.png",
      overview: "Modern e-commerce mobile application designed to enhance the shopping experience with intuitive user flow and engaging visual design.",
      problem: "Users needed a more intuitive way to browse and purchase fashion items online with better product discovery.",
      process: [
        "User research and persona development",
        "Competitive analysis and market research", 
        "Information architecture and user flows",
        "Wireframing and low-fidelity prototypes",
        "High-fidelity UI design and iterations"
      ],
      wireframes: ["/cover page of plant.png"],
      uiScreens: ["/cover page of plant.png"],
      mockups: ["/cover page of plant.png"]
    },
    "Plant Shop Mobile App": {
      hero: "/cover page of plant.png",
      overview: "Clean and minimalist plant shopping experience with product discovery features.",
      problem: "Plant enthusiasts needed a dedicated platform to discover and purchase plants with care information.",
      process: [
        "Market research and user interviews",
        "User journey mapping",
        "Mobile-first responsive design",
        "Prototyping and user testing"
      ],
      wireframes: ["/cover page of plant.png"],
      uiScreens: ["/cover page of plant.png"],
      mockups: ["/cover page of plant.png"]
    },
    "Premium Sneaker Shopping App": {
      hero: "/covr page.png",
      overview: "Professional service platform with streamlined user journey and modern aesthetics.",
      problem: "Service providers needed a better way to showcase services and manage client relationships.",
      process: [
        "Stakeholder interviews and requirements",
        "Service design and user flows",
        "Brand identity and visual design",
        "Responsive web design",
        "Interactive prototyping"
      ],
      wireframes: ["/CS sneakr prt 1.png", "/CS sneakr prt 2.png"],
      uiScreens: ["/CS sneakr prt 3.png", "/covr page.png"],
      mockups: ["/covr page.png", "/CS sneakr prt 2.png"]
    },
    "Dashboard UI Concept": {
      hero: "/covr page.png",
      overview: "Data-driven dashboard with complex information architecture and visual hierarchy.",
      problem: "Users needed better ways to visualize and analyze complex data sets.",
      process: [
        "Data analysis and user requirements",
        "Information architecture design",
        "Dashboard layout and wireframing",
        "Visual design and data visualization"
      ],
      wireframes: ["/covr page.png"],
      uiScreens: ["/covr page.png"],
      mockups: ["/covr page.png"]
    }
  };

  const content = caseStudyContent[project.title];
  if (!content) return null;

  return (
    <div className="case-study-overlay" onClick={onClose}>
      <div className="case-study-modal" onClick={(e) => e.stopPropagation()}>
        <div className="case-study-header">
          <button className="close-btn" onClick={onClose}>×</button>
          <h2>{project.title}</h2>
        </div>

        <div className="case-study-content">
          {/* All Images - Full Width Scrollable */}
          <div className="image-gallery">
            {content.wireframes.map((image, index) => (
              <div key={index} className="gallery-item">
                <img src={image} alt={`Image ${index + 1}`} />
              </div>
            ))}
            {content.uiScreens.map((image, index) => (
              <div key={index} className="gallery-item">
                <img src={image} alt={`Image ${index + 1}`} />
              </div>
            ))}
            {content.mockups.map((image, index) => (
              <div key={index} className="gallery-item">
                <img src={image} alt={`Image ${index + 1}`} />
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default CaseStudy;
